def solve(grid: Array[Array[Long]], k: Long): Long = {
    val m = grid.length
    if (m == 0) return 0L
    val n = grid(0).length
    var count = 0L
    for (i <- 0 until m) {
        for (j <- 0 until n) {
            if (grid(i)(j) != 0L) {
                val queue = Queue[(Int, Int)]()
                queue.enqueue((i, j))
                var sumVal = grid(i)(j)
                grid(i)(j) = 0L
                while (queue.nonEmpty) {
                    val (x, y) = queue.dequeue
                    for (dx <- List(-1, 1, 0, 0); dy <- List(0, 0, -1, 1)) {
                        val nx = x + dx
                        val ny = y + dy
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid(nx)(ny) != 0L) {
                            sumVal += grid(nx)(ny)
                            grid(nx)(ny) = 0L
                            queue.enqueue((nx, ny))
                        }
                    }
                }
                if (sumVal % k == 0) {
                    count += 1
                }
            }
        }
    }
    count
}
